#include <iostream>
#include <iomanip>
#include <vector>
#include <sstream>

class TemperatureConverter {
private:
    double m_celsiusValue;

public:
    TemperatureConverter() : m_celsiusValue(0.0) {}

    TemperatureConverter& setCelsius(double c) {
        m_celsiusValue = c;
        return *this;
    }

    double getFahrenheit() {
        return (m_celsiusValue * 9.0 / 5.0) + 32.0;
    }
};

int main() {
    std::ostringstream oss;
    oss << std::fixed << std::setprecision(2);

    std::vector<std::pair<double, double>> testData = {
        {25.0, 77.00}, {0.0, 32.00}, {100.0, 212.00}, {-40.0, -40.00}, {37.0, 98.60}, {-17.78, 0.00}
    };
    TemperatureConverter converter;

    for (const auto& test : testData) {
        converter.setCelsius(test.first);
        oss << converter.getFahrenheit() << "\n";
    }

    std::cout << oss.str();
    return 0;
}
